import puppeteer from 'puppeteer';
import * as path from 'path';

const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

async function run() {
    console.log("Starting real logo upload...");
    const browser = await puppeteer.launch({ headless: true });
    const page = await browser.newPage();

    console.log(`Going to settings page`);
    await page.goto(`http://localhost:3000/admin/settings`, { waitUntil: 'domcontentloaded' });

    // Wait for the form to load
    await page.waitForFunction(() => {
        const input = document.querySelector('input[name="whatsapp_number"]');
        return input && input.value.length > 0;
    });

    console.log('Form loaded, attaching logo file...');

    // There only one file input on settings page
    const fileInput = await page.$('input[type="file"]');
    const filePath = path.resolve('.gemini/antigravity/brain/2da29ae0-fb61-4886-ad2e-9072a5a0d29a/euromar_immo_logo_1772471447851.png');
    await fileInput.uploadFile(filePath);

    await sleep(2000); // Give it a sec to visually update

    // Submit
    await page.click('button[type="submit"]');

    console.log('Submitted form, waiting for response...');

    // Wait for either success message or error
    try {
        await page.waitForFunction(() => {
            return document.body.innerText.includes("Paramètres sauvegardés avec succès !") ||
                document.body.innerText.includes("Erreur") ||
                document.body.innerText.includes("unexpected response");
        }, { timeout: 15000 });

        const text = await page.evaluate(() => document.body.innerText);
        if (text.includes("Paramètres sauvegardés avec succès !")) {
            console.log("Success! Actual logo uploaded.");
        } else {
            console.log("Found error on page while saving settings!");
        }
    } catch (e) {
        console.log("Timeout waiting for response.");
    }

    await sleep(1000);
    await browser.close();
}

run().catch(console.error);

import { createClient } from '@supabase/supabase-js';
import * as fs from 'fs';
import * as path from 'path';
import * as dotenv from 'dotenv';

// Load from .env.local instead of just .env
dotenv.config({ path: '.env.local' });

async function uploadLogoAndSetDB() {
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
    const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
    const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY || supabaseKey;

    if (!supabaseUrl || !supabaseKey) {
        console.error("Missing supabase env vars!");
        process.exit(1);
    }

    // Attempt with whichever key we have
    const supabase = createClient(supabaseUrl, supabaseServiceKey);

    const logoPath = '/Users/marouanekdidou/.gemini/antigravity/brain/2da29ae0-fb61-4886-ad2e-9072a5a0d29a/euromar_luxury_logo_1772472024601.png';

    if (!fs.existsSync(logoPath)) {
        console.error("Logo file not found at", logoPath);
        process.exit(1);
    }

    const fileBuffer = fs.readFileSync(logoPath);
    const fileName = `generated_logo_${Date.now()}.png`;

    console.log("Uploading logo to Supabase Storage...");
    const { data: uploadData, error: uploadError } = await supabase.storage
        .from('properties')
        .upload(fileName, fileBuffer, {
            contentType: 'image/png'
        });

    if (uploadError) {
        console.error("Storage upload error:", uploadError);
        process.exit(1);
    }

    const { data: publicUrlData } = supabase.storage.from('properties').getPublicUrl(fileName);
    const publicUrl = publicUrlData.publicUrl;

    console.log("Uploaded! Public URL:", publicUrl);

    console.log("Updating settings table...");
    // Just find the single row
    const { data: settingsRow } = await supabase.from('settings').select('id').limit(1).single();

    if (settingsRow) {
        const { error: updateError } = await supabase
            .from('settings')
            .update({ logo_url: publicUrl })
            .eq('id', settingsRow.id);

        if (updateError) {
            console.error("DB update error:", updateError);
        } else {
            console.log("SUCCESS! Database updated with new logo.");
        }
    } else {
        console.log("No settings row found. Consider saving from dashboard UI first.");
    }
}

uploadLogoAndSetDB().catch(console.error);

// Using pure canvas to make white transparent
const { Canvas, Image } = require('canvas');
const fs = require('fs');

function makeTransparent() {
    const inputPath = '/Users/marouanekdidou/.gemini/antigravity/brain/2da29ae0-fb61-4886-ad2e-9072a5a0d29a/large_emblem_logo_1772472178266.png';
    const outputPath = '/Users/marouanekdidou/Desktop/Finaaaal/transparent_emblem.png';

    fs.readFile(inputPath, (err, fileData) => {
        if (err) throw err;
        const img = new Image();
        img.onload = () => {
            const canvas = new Canvas(img.width, img.height);
            const ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0, img.width, img.height);

            const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const data = imageData.data;

            for (let i = 0; i < data.length; i += 4) {
                if (data[i] > 240 && data[i + 1] > 240 && data[i + 2] > 240) {
                    data[i + 3] = 0; // alpha
                }
            }

            ctx.putImageData(imageData, 0, 0);

            const out = fs.createWriteStream(outputPath);
            const stream = canvas.createPNGStream();
            stream.pipe(out);
            out.on('finish', () => console.log('Transprency done! saved to', outputPath));
        };
        img.onerror = err => { throw err };
        img.src = fileData;
    });
}
makeTransparent();

"use server";

import { createClient } from "@/utils/supabase/server";
import { revalidatePath } from "next/cache";

export async function getProperties() {
    const supabase = await createClient();
    const { data: properties, error } = await supabase
        .from('properties')
        .select('*')
        .order('created_at', { ascending: false });

    if (error) {
        console.error("Error fetching properties:", error);
        return [];
    }
    return properties;
}

export async function getPropertyById(id: string) {
    const supabase = await createClient();
    const { data: property, error } = await supabase
        .from('properties')
        .select('*')
        .eq('id', id)
        .single();

    if (error) {
        console.error(`Error fetching property ${id}:`, error);
        return null;
    }
    return property;
}

export async function createProperty(formData: FormData) {
    try {
        const supabase = await createClient();

        const title = formData.get("title")?.toString();
        const description = formData.get("description")?.toString();
        const type = formData.get("type")?.toString();
        const transactiontype = formData.get("transactionType")?.toString() || formData.get("transactiontype")?.toString();
        const price = formData.get("price")?.toString();
        const priceNumericStr = formData.get("priceNumeric")?.toString() || formData.get("pricenumeric")?.toString();

        const errors: string[] = [];
        if (!title) errors.push("Le titre est requis.");
        if (!description) errors.push("La description est requise.");
        if (!type) errors.push("Le type de bien est requis.");
        if (!transactiontype) errors.push("Le type de transaction est requis.");
        if (!price) errors.push("Le prix affiché est requis.");
        if (!priceNumericStr) errors.push("La valeur numérique du prix est requise.");

        if (errors.length > 0) {
            return { success: false, error: errors.join(" ") };
        }

        const pricenumeric = Number(priceNumericStr);

        const propertyData = {
            title,
            description,
            type,
            transactiontype,
            price,
            pricenumeric,
            status: formData.get("status")?.toString(),
            location: formData.get("location")?.toString(),
            city: formData.get("city")?.toString(),
            bedrooms: Number(formData.get("bedrooms")) || null,
            bathrooms: Number(formData.get("bathrooms")) || null,
            surface: Number(formData.get("surface")) || null,
            yearbuilt: Number(formData.get("yearBuilt") || formData.get("yearbuilt")) || null,
            amenities: formData.get("amenities") ? JSON.parse(formData.get("amenities") as string) : [],
            images: formData.get("images") ? JSON.parse(formData.get("images") as string) : [],
        };

        const { data, error } = await supabase
            .from('properties')
            .insert([propertyData])
            .select();

        if (error) throw error;

        revalidatePath("/admin");
        revalidatePath("/proprietes");
        revalidatePath("/");

        return { success: true, data };
    } catch (error: any) {
        console.error("Error creating property:", error);
        return { success: false, error: error.message || "Failed to create property" };
    }
}

