        if (!price) errors.push("Le prix affiché est requis.");
        if (!priceNumericStr) errors.push("La valeur numérique du prix est requise.");

        if (errors.length > 0) {
            return { success: false, error: errors.join(" ") };
        }

        const pricenumeric = Number(priceNumericStr);

        const propertyData = {
            title,
            description,
            type,
            transactiontype,
            price,
