                                            {lead.status || 'Nouveau'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-right text-sm font-medium">
                                        <form action={async () => {
                                            "use server";
                                            const newStatus = lead.status === 'Nouveau' || !lead.status ? 'Traité' : 'Nouveau';
                                            await updateLeadStatus(lead.id, newStatus);
