                            <input type="file" multiple accept="image/*" onChange={handleFileSelect} className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0 file:text-sm file:font-semibold file:bg-accent/10 file:text-accent hover:file:bg-accent/20 transition-colors" />
                            {imageFiles.length > 0 && (
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mt-4">
                                    {imageFiles.map((file, idx) => (
                                        <div key={idx} className="relative group rounded-md overflow-hidden border border-gray-200">
                                            <div className="h-24 bg-gray-100 bg-cover bg-center" style={{ backgroundImage: `url(${URL.createObjectURL(file)})` }}></div>
                                            <button type="button" onClick={() => handleRemoveImageFile(idx)} className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                                                <X className="w-3 h-3" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="border-t border-gray-200 pt-6">
                        <h2 className="text-lg font-semibold text-primary mb-2">Prestations (Amenities)</h2>
                        <div className="flex gap-2 mb-3">
                            <input
                                type="text"
                                value={newAmenity}
                                onChange={(e) => setNewAmenity(e.target.value)}
                                onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); handleAddAmenity(); } }}
                                placeholder="Ex: Piscine Chauffée"
                                className="flex-1 border border-gray-300 rounded-md px-4 py-2 outline-none focus:ring-2 focus:ring-accent"
                            />
                            <button type="button" onClick={handleAddAmenity} className="bg-gray-200 hover:bg-gray-300 text-gray-700 px-4 py-2 rounded-md font-medium flex items-center gap-1 transition-colors">
                                <Plus className="w-4 h-4" /> Ajouter
                            </button>
                        </div>
                        {amenities.length > 0 && (
                            <div className="flex flex-wrap gap-2">
                                {amenities.map((amenity, idx) => (
                                    <span key={idx} className="bg-accent/10 border border-accent/20 text-primary px-3 py-1 rounded-full text-sm flex items-center gap-2">
                                        {amenity}
                                        <button type="button" onClick={() => handleRemoveAmenity(amenity)} className="text-gray-500 hover:text-red-500">
                                            <X className="w-3 h-3" />
                                        </button>
                                    </span>
                                ))}
                            </div>
                        )}
                        {amenities.length === 0 && <p className="text-gray-400 text-sm italic">Aucune prestation ajoutée.</p>}
                    </div>
                </div>

                <div className="pt-4 flex justify-end">
                    <button
                        type="submit"
                        disabled={isPending}
                        className="bg-primary hover:bg-gray-800 text-white px-8 py-3 rounded-md font-medium transition-colors disabled:opacity-50 text-lg shadow-lg"
                    >
                        {isPending ? "Sauvegarde..." : "Publier la Propriété"}
                    </button>
                </div>
            </form>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { getSettings, updateSettings } from "@/app/actions/settings-actions";

export default function SettingsPage() {
    const [settings, setSettings] = useState<any>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [message, setMessage] = useState("");
    const [logoPreview, setLogoPreview] = useState<string | null>(null);

    useEffect(() => {
        async function loadSettings() {
            const data = await getSettings();
            setSettings(data);
            if (data?.logo_url) {
                setLogoPreview(data.logo_url);
            }
        }
        loadSettings();
    }, []);

    const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            setLogoPreview(URL.createObjectURL(file));
        }
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setIsSaving(true);
        setMessage("");

        const formData = new FormData(e.currentTarget);
        const result = await updateSettings(formData);

        if (result?.success) {
            setMessage("Paramètres sauvegardés avec succès !");
        } else {
            setMessage("Erreur lors de la sauvegarde.");
        }
        setIsSaving(false);
    };

    if (!settings) return <div className="text-gray-500">Chargement des paramètres...</div>;

    return (
        <div className="max-w-4xl">
            <h1 className="text-3xl font-bold text-gray-900 mb-8">Paramètres Globaux</h1>

            <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-sm border border-gray-100 divide-y divide-gray-100">
                {/* Logo Section */}
                <div className="p-8">
                    <h2 className="text-xl font-serif text-primary mb-6">Logo du site</h2>
                    <div className="flex items-start gap-6">
                        <div className="shrink-0 w-32 h-32 bg-gray-50 border-2 border-dashed border-gray-200 rounded-lg flex items-center justify-center overflow-hidden">
                            {logoPreview ? (
                                <img src={logoPreview} alt="Logo" className="max-w-full max-h-full object-contain" />
                            ) : (
                                <span className="text-gray-400 text-sm">Aucun logo</span>
                            )}
                        </div>
                        <div className="flex-1">
                            <label className="block text-sm font-medium text-gray-700 mb-2">Importer un nouveau logo</label>
                            <input
                                type="file"
                                name="logoFile"
                                accept="image/*"
                                onChange={handleLogoChange}
                                className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0 file:text-sm file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20 transition-colors"
                            />
                            <p className="text-xs text-gray-500 mt-2">Format recommandé : PNG avec fond transparent. Max 2MB.</p>
                            {/* Hidden input to keep track of current URL if not replaced by file */}
                            <input type="hidden" name="logo_url" value={settings.logo_url || ""} />
                        </div>
                    </div>
                </div>

                {/* Contact Section */}
                <div className="p-8">
                    <h2 className="text-xl font-serif text-primary mb-6">Contact & WhatsApp</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">Numéro WhatsApp (avec indicatif)</label>
                            <input
                                type="text"
                                name="whatsapp_number"
                                defaultValue={settings.whatsapp_number}
                                className="w-full border border-gray-200 rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-accent focus:border-transparent"
                                placeholder="+212600692922"
                            />
                            <p className="text-xs text-gray-500 mt-1">Utilisé pour le bouton flottant et les modals de paiement.</p>
                        </div>
