                        {/* Amenities */}
                        {property.amenities && property.amenities.length > 0 && (
                            <div>
                                <h2 className="font-serif text-2xl text-primary mb-6">Prestations & Équipements</h2>
                                <ul className="grid grid-cols-1 md:grid-cols-2 gap-y-4 gap-x-8">
