                                        </div>
                                    </Link>
                                    <div className="p-5">
                                        <h3 className="font-serif text-lg text-primary mb-1 group-hover:text-accent transition-colors">
                                            <Link href={`/proprietes/${similar.id}`}>
                                                {similar.title}
                                            </Link>
                                        </h3>
                                        <p className="text-sm text-gray-500">{similar.location}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Payment Modal */}
                <PaymentModal
