                        : `${((totalPrice || 0) * 0.1).toLocaleString('fr-FR')} DH (10% du séjour)`}
                    totalAmount={property.type === 'Location' && totalPrice ? `${totalPrice.toLocaleString('fr-FR')} DH` : undefined}
                    settings={settings}
                />
            </div>
        </div>
    );
}

